import point from './point.js';

let factories = {
	point
}

function deepClone(data){
	let ret = Array.isArray(data) ? [] : {};
	for( let key in data ){
		let value = data[key];
		if( typeof value === 'object' ){
			ret[key] = deepClone(value)
		}else{
			ret[key] = value;
		}
	}
	return ret;
}

export default {
	createShape(core, shapeType){
		let factory = factories[shapeType];
		if( factory ){
			let ret = deepClone(factory.config);
			Object.defineProperty(ret, 'type', {
				writable: false
			});
			Object.defineProperty(ret, 'dataKey', {
				writable: false,
				value: core.nowDataKey
			});
			return ret;
		}
	},
	initShape(core, shape, x, y){
		return factories[shape.type].init(core, shape, x, y);
	},
	readyOperate(core, shape){
		return factories[shape.type].ready(core, shape);
	},
	readyOperateEnd(core, shape){
		return factories[shape.type].readyEnd(core, shape);
	},
	drawShape(core, shape){
 
		factories[shape.type].draw(core, shape);
	},
	shapeIsSelected(core, shape, x, y){

		return factories[shape.type].isSelected(core, shape, x, y);
	},
	selectShape(core, shape, x, y){

		return factories[shape.type].select(core, shape, x, y);
	},
	hasAddPoint(shapeType){

		return typeof factories[shapeType].addPoint === 'function';
	},
	addPoint(core, shape, x, y){
		let factory = factories[shape.type];
		if( factory.addPoint ){
			return factory.addPoint(core, shape, x, y);
		}else{
			console.warn('该类形状没有添加顶点的接口');
		}
	},
	movePoint(core, shape, x, y){

		return factories[shape.type].move(core, shape, x, y);
	},
	moveEnd(core, shape, x, y){

		factories[shape.type].moveEnd(core, shape, x, y);
	},
	deletePoint(core, shape, x, y){

		factories[shape.type].delete(core, shape, x, y);
	}
}
