export default {
	// 调整 canvas 画布和画版的大小
	setSize(w, h){
		w = Math.floor(w);
		h = Math.floor(h);

		this.width = w;
		this.height = h;

		this.canvas.width = w;
		this.canvas.height = h;

		this.canvas.style.width = `${w}px`;
		this.canvas.style.height = `${h}px`;
	},
	fill(){
		let 
			parentNodeRect = this.canvas.parentNode.getBoundingClientRect(),
			parentWidth = parentNodeRect.width,
			parentHeight = parentNodeRect.height;

		this.setSize( Math.floor(parentNodeRect.width), Math.floor(parentNodeRect.height) )
	},
	contain(ratio){
		let 
			parentNodeRect = this.canvas.parentNode.getBoundingClientRect(),
			parentWidth = parentNodeRect.width,
			parentHeight = parentNodeRect.height,
			parentRatio = parentWidth / parentHeight,

			width, height;

		if( ratio > parentRatio ){
			width = Math.floor(parentWidth);
			height = Math.floor(parentWidth / ratio);
		}else{
			width = Math.floor(parentHeight * ratio);
			height = Math.floor(parentHeight);
		}
		this.setSize(width, height);
	}
}