export default {
	config: {
		type: 'point',
		color: 'rgb(0,0,0)',
		radius: 3,
		selectedRadius: 5,
		lineWidth: 0,
		hover: false,
		selected: true,
	},
	draw(core, shapeMsg){
		let {
				x, y,
				radius, selectedRadius, color, 
				hover, selected, lineWidth
			} = shapeMsg,
			ctx = core.ctx;

	  ctx.beginPath();

	  ctx.arc( x, y,
	  	hover || selected ? selectedRadius : radius,
	  	0, Math.PI * 2 );

	  ctx.closePath();
	  ctx.lineWidth = lineWidth;
	  ctx.fillStyle = color;

	  ctx.stroke();
	  ctx.fill();
	},
	init(core, shapeMsg, x, y){
		shapeMsg.x = x;
		shapeMsg.y = y;
	},
	ready(core, shapeMsg, x, y){

	},
	readyEnd(core, shapeMsg, x, y){

	},
	hasPoint(core, shapeMsg){
		if( shapeMsg.x && shapeMsg.y ){
			return true;
		}
		return false;
	},
	isSelected(core, shapeMsg, x, y){
		return Math.floor(Math.sqrt(
			Math.pow( shapeMsg.x - x, 2 ),
			Math.pow( shapeMsg.y - y, 2 )
		)) < shapeMsg.radius;
	},
	select(core, shapeMsg, x, y){
		shapeMsg.selected = true;
	},
	move(core, shapeMsg, x, y){
		shapeMsg.x = x;
		shapeMsg.y = y;
	},
	moveEnd(core, shapeMsg, x, y){
		shapeMsg.selected = false;
	},
	delete(core, shapeMsg, x, y){
		core.removeShape(shapeMsg);
		shapeMsg = null;
	}
}