import Core from './core/core.js';

export { drawState, selectRangeType } from './core/core.js';

export default function Draw(canvas){

	let core = new Core(canvas)

	Object.assign(this, {
		// 设置canvas大小相关
		fill(){
			core.fill();
			return this;
		},
		contain(ratio){
			core.contain(ratio);
			return this;
		},
		setSize(w, h){
			core.setSize(w, h);
			return this;
		},
		clearAll(){
			core.clearAll();
			return this;
		},
		draw(){
			core.clearAll();
			core.draw();
			return this;
		},
		initEvent(){
			core.initEvent();
			return this;
		},
		destroyEvent(){
			if( core.destroyEvent ){
				core.destroyEvent();
			}
			return this;
		},
		setState(state, message){
			if( drawState[state] ){
				core.state = drawState[state];
				switch( state ){
					case drawState.new:
						core.readyAddShapeType = message;
						break;
					case drawState.add:
						core.operatedShape = message;
						break;
				}
			}
			return this;
		},
		setStateAutoProcess(option){
			let stateAutoProcess = core.stateAutoProcess;
			for( let key in option ){
				if( stateAutoProcess[key] ){
					stateAutoProcess[key] = option[key];
				}
			}
			return this;
		},
		destroy(){
			core.destroy();
			core = null;
		},
		addShape(shapeType){
			core.addShape(shapeType);
			return core.addShape(shapeType);;
		},
		readyOperateShape(shape){
			core.readyOperateShape(shape);
			core.clearAll();
			core.draw();
			return this;
		},
		readyOperateShapeEnd(shape){
			core.readyOperateShapeEnd(shape);
			core.clearAll();
			core.draw();
			return this;
		},
		removeShape(shape){
			core.removeShape(shape);
			core.clearAll();
			core.draw();
			return this;
		},
		setData(type){
			core.nowDataKey = type;
			return this;
		},
		getData(type){
			return core.getData(type);
		},
		addData(type, isChange){
			core.addData(type, isChange);
			return this;
		},
	});
}
