import shapeFactory from '../shape_factory/shape_factory.js';
import { drawState, selectRangeType } from './core.js';

export default {
	initEvent(){
		let actualOperatedShape = null;
		this.canvas.oncontextmenu = function(e){
	    //取消默认的浏览器自带右键 很重要！！
	    e.preventDefault();
		}
		this.canvas.onmousedown = (e)=>{
			let x = e.offsetX,
					y = e.offsetY,
					selectedShape,
					{
						selectRange, 
						allowNewToSelect,
						allowSelectNoneToNew,
						allowAddToSelect 
					} = this.stateAutoProcess;
			// 选择鼠标点击到的形状
			switch( selectRange ){
				case selectRangeType.all:
					for( let key in this.data ){
						let data = this.data[key];
						for( let i = 0, len = data.length; i < len; i++ ){
							let shape = data[i]
							if( shapeFactory.shapeIsSelected(this, shape, x, y) ){
								selectedShape = shape;
								break;
							}
						}
					}
					break;
				case selectRangeType.operationShape:
					if( this.operatedShape && shapeFactory.shapeIsSelected(this, this.operatedShape, x, y) ){
						selectedShape = this.operatedShape;
					}
					break;
			}
			if( e.button === 0 ){
				// 改变状态
				switch(this.state){
					case drawState.new:
						if( allowNewToSelect && selectedShape ){
							this.state = drawState.select;
							actualOperatedShape = selectedShape;
						}
						break;
					case drawState.select:
						if( allowSelectNoneToNew && !selectedShape && this.readyAddShapeType ){
							this.state = drawState.new;
						}
						break;
					case drawState.add:
						if( allowAddToSelect && selectedShape ){
							this.state = drawState.select;
						}
						break;
				}
				// 执行操作
				switch(this.state){
					case drawState.new:
						this.operatedShape = actualOperatedShape = this.addShape(this.readyAddShapeType);
						shapeFactory.initShape(this, this.operatedShape, x, y);
						this.reDraw();
						if( shapeFactory.hasAddPoint(this.readyAddShapeType) ){
							this.state = drawState.add;
						}
						break;
					case drawState.add:
						if( this.operatedShape ){
							actualOperatedShape = this.operatedShape;
							shapeFactory.addPoint(this, actualOperatedShape, x, y);
							this.reDraw();
						}
						break;
					case drawState.select:
						if( selectedShape ){
							actualOperatedShape = selectedShape;
							shapeFactory.selectShape(this, actualOperatedShape, x, y);
							this.reDraw();
						}
						break;
					default:
						break;
				}
			}else if( e.button === 2 ){
				if( selectedShape ){
					shapeFactory.deletePoint(this, selectedShape, x, y);
					this.reDraw();
				}
			}
		}
		this.canvas.onmousemove = (e)=>{
			if(actualOperatedShape){
				let x = e.offsetX,
						y = e.offsetY;

				shapeFactory.movePoint(this, actualOperatedShape, x, y);
				this.reDraw();
			}
		}
		this.canvas.onmouseup = (e)=>{
			if(actualOperatedShape){
				let x = e.offsetX,
						y = e.offsetY;
				shapeFactory.moveEnd(this, actualOperatedShape, x, y);
				actualOperatedShape = null;
				this.reDraw();
			}
		}

		this.destroyEvent = function(){
			this.canvas.oncontextmenu = null;
			this.canvas.onmousedown = null;
			this.canvas.onmousemove = null;
			this.canvas.onmouseup = null;
		}
	},
}