import shapeFactory from '../shape_factory/shape_factory.js';
import objectFit from './object_fit.js';
import event from './event.js';
import data from './data.js';

export const drawState = {
	add: 'add',
	select: 'select',
	new: 'new',
	none: 'none'
}

export const selectRangeType = {
	all: 'all',
	operationShape: 'operationShape',
}

export default function Core(canvas){
	this.canvas = canvas;
	this.ctx = canvas.getContext('2d');

	this.width = canvas.width;
	this.height = canvas.height;

	this.nowDataKey = 'default';
	this.data = {
		[this.nowDataKey]: []
	};

	this.state = drawState.none;
	this.operatedShape = null;
	this.readyAddShapeType = null;
	this.stateAutoProcess = {		//主要是涉及状态自动变化流程的参数
		selectRange: selectRangeType.all,
		allowNewToSelect: true,
		allowSelectNoneToNew: true,
		allowAddToSelect: true,
	};
	this.state = drawState.new;
	this.readyAddShapeType = 'point';
}

Object.assign( Core.prototype,
	event,
	objectFit,
	data,
	{
		draw(){
			for( let key in this.data ){
				this.data[key].forEach((item)=>{
					shapeFactory.drawShape(this, item);
				});
			}
		},
		clearAll(){
			// console.log('clearAll:', clearAll);
			// console.log('this.data:', this.data);
			this.ctx.clearRect(0, 0, this.width, this.height);
		},
		reDraw(){
			this.clearAll();
			this.draw();
		},
		destroy(){
			if( this.destroyEvent ){
				this.destroyEvent();
			}
			this.canvas = null;
			this.ctx = null;

			this.width = null;
			this.height = null;

			this.shapes = null;

			this.state = null;
			this.operatedShape = null;
			this.readyAddShapeType = null;
			this.stateAutoProcess = null;
		}
	}
)